286→        }
287→        if(!originalJournal){
288→            throw {status: 404, error: 'original post no longer exists'};
289→        }
290→        if(originalJournal.privacy !== 'public'){
291→            throw {status: 403, error: 'cannot repost a private post'};
292→        }
293→        if(originalJournal.user_id === userId){
294→            throw {status: 403, error: 'cannot repost your own post'};
295→        }
296→
297→        ultimateSourceId = originalJournal.id;
298→        ultimateSourceUserId = originalJournal.user_id;
299→        ultimateSourceTitle = originalJournal.title;
300→    }
301→
302→    // Check for duplicate repost
303→    const {data: existingRepost, error: errorExisting} = await supabase
304→        .from('journals')
305→        .select('id')
306→        .eq('user_id', userId)
307→        .eq('repost_source_journal_id', ultimateSourceId)
308→        .eq('is_repost', true)
309→        .maybeSingle();
310→
311→    if(errorExisting){
312→        console.error('supabase error while checking existing repost:', errorExisting.message);
313→        throw {status: 500, error: 'supabase error while checking existing repost'};
314→    }
315→
316→    if(existingRepost){
317→        throw {status: 409, error: 'you have already reposted this post'};
318→    }
319→
320→    const repostTitle = `Repost: ${ultimateSourceTitle || 'Untitled'}`;
321→
322→    const {data: insertedRepost, error: errorInsertRepost} = await supabase
323→        .from('journals')
324→        .insert({
325→            user_id: userId,
326→            is_repost: true,
327→            repost_source_journal_id: ultimateSourceId,
328→            repost_caption: caption || null,
329→            post_type: 'text',
330→            content: null,
331→            title: repostTitle.length > 255 ? repostTitle.substring(0, 255) : repostTitle,
332→            privacy: 'public'
333→        })
334→        .select('id')
335→        .single();
336→
337→    if(errorInsertRepost){
338→        console.error('supabase error while inserting repost:', errorInsertRepost.message);
339→        throw {status: 500, error: 'supabase error while inserting repost'};
340→    }
341→
342→    // Notify the original author (skip if self)
343→    const isOwnContent = userId === ultimateSourceUserId;
344→    if(!isOwnContent){
345→        const {error: errorNotif} = await supabase
346→            .from('notifications')
347→            .insert({
348→                sender_id: userId,
349→                receiver_id: ultimateSourceUserId,
350→                journal_id: ultimateSourceId,
351→                repost_journal_id: insertedRepost.id,
352→                type: 'repost',
353→                read: false
354→            });
355→
356→        if(errorNotif){
357→            console.error('supabase error while inserting repost notification:', errorNotif.message);
358→        }
359→    }
360→
361→    return {message: 'repost created', repostId: insertedRepost.id, sourceJournalId: ultimateSourceId};
362→}
